-- ============================================================================
-- Migration 067: Load Sales Pipeline milestones from the master spreadsheet
-- (Sales Progress tabs LP / RP / RL / N5=Ardan View) for Bridge Property Group.
-- Per-stage dates are written from the sheet only where the sheet has a valid
-- value (COALESCE keeps existing data when the sheet cell is blank/a typo).
-- handover_date is authoritative: the real completion date for handed-over units
-- (parsed from the "Handover Complete - DD-Mon-YY" comment) and NULL otherwise,
-- which clears false "handed over" flags on in-progress units. For completed
-- units, kitchen/snag/drawdown are backfilled so progress reads 100%.
-- Social-housing (Clúid) units are not part of the sales pipeline and are skipped.
-- Idempotent / safe to re-run.
-- ============================================================================

DROP TABLE IF EXISTS usp_milestones_backup_2026_06_04;
CREATE TABLE usp_milestones_backup_2026_06_04 AS
SELECT usp.* FROM unit_sales_pipeline usp JOIN units u ON u.id=usp.unit_id
WHERE u.development_id IN ('e0833063-55ac-4201-a50e-f329c090fbd6','84a559d1-89f1-4eb6-a48b-7ca068bcc164','39c49eeb-54a6-4b04-a16a-119012c531cb','34316432-f1e8-4297-b993-d9b5c88ee2d8');


-- Longview Park: 62 units
UPDATE unit_sales_pipeline usp SET
  release_date          = COALESCE(v.release::date,   usp.release_date),
  sale_agreed_date      = COALESCE(v.agreed::date,    usp.sale_agreed_date),
  deposit_date          = COALESCE(v.deposit::date,   usp.deposit_date),
  contracts_issued_date = COALESCE(v.contracts::date, usp.contracts_issued_date),
  queries_raised_date   = COALESCE(v.qraised::date,   usp.queries_raised_date),
  queries_replied_date  = COALESCE(v.qreplied::date,  usp.queries_replied_date),
  signed_contracts_date = COALESCE(v.signed::date,    usp.signed_contracts_date),
  counter_signed_date   = COALESCE(v.counter::date,   usp.counter_signed_date),
  handover_date         = CASE WHEN v.completed::boolean THEN COALESCE(v.handover::date, usp.handover_date) ELSE NULL END,
  snag_date     = CASE WHEN v.completed::boolean THEN COALESCE(usp.snag_date, v.snag::date, (COALESCE(v.handover::date, usp.handover_date::date) - 14)) ELSE COALESCE(v.snag::date, usp.snag_date) END,
  drawdown_date = CASE WHEN v.completed::boolean THEN COALESCE(usp.drawdown_date, (COALESCE(v.handover::date, usp.handover_date::date) - 3)) ELSE usp.drawdown_date END,
  kitchen_date  = CASE WHEN v.completed::boolean THEN COALESCE(usp.kitchen_date, v.counter::date, v.signed::date, (COALESCE(v.handover::date, usp.handover_date::date) - 21)) ELSE usp.kitchen_date END,
  sale_price = COALESCE(v.price::numeric, usp.sale_price),
  comments   = COALESCE(NULLIF(v.comments,''), usp.comments),
  updated_at = now()
FROM (VALUES
