-- Ensure every handed-over (completed) unit reads 100%: backfill any milestone
-- the spreadsheet left blank with the handover date (it logically occurred by handover).
UPDATE unit_sales_pipeline usp SET
  release_date          = COALESCE(usp.release_date,          usp.handover_date),
  sale_agreed_date      = COALESCE(usp.sale_agreed_date,      usp.handover_date),
  deposit_date          = COALESCE(usp.deposit_date,          usp.handover_date),
  contracts_issued_date = COALESCE(usp.contracts_issued_date, usp.handover_date),
  signed_contracts_date = COALESCE(usp.signed_contracts_date, usp.handover_date),
  counter_signed_date   = COALESCE(usp.counter_signed_date,   usp.handover_date),
  kitchen_date          = COALESCE(usp.kitchen_date,          usp.handover_date),
  snag_date             = COALESCE(usp.snag_date,             usp.handover_date),
  drawdown_date         = COALESCE(usp.drawdown_date,         usp.handover_date)
FROM units u
WHERE usp.unit_id = u.id
  AND u.development_id IN ('e0833063-55ac-4201-a50e-f329c090fbd6','84a559d1-89f1-4eb6-a48b-7ca068bcc164','39c49eeb-54a6-4b04-a16a-119012c531cb','34316432-f1e8-4297-b993-d9b5c88ee2d8')
  AND usp.sale_type <> 'social'
  AND usp.handover_date IS NOT NULL;
